import React, { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

function ClientDashboard() {
  const navigate = useNavigate();
  const userEmail = localStorage.getItem("userEmail");

  useEffect(() => {
    const isLoggedIn = localStorage.getItem("isLoggedIn");
    
    // SECURITY ACTION: Redirect to login if not authenticated
    if (!isLoggedIn) {
      alert("Access Denied! Please login first.");
      navigate('/login');
    }
  }, [navigate]);

  const handleLogout = () => {
    localStorage.clear(); // Clear session
    navigate('/login');   // Go back to login
  };

  return (
    <div className="container py-5">
      <div className="card p-5 shadow-sm border-0 bg-white text-center">
        <h1 className="display-5 fw-bold text-success">Client Dashboard</h1>
        <p className="lead text-muted">Welcome back, <strong>{userEmail}</strong>!</p>
        <hr className="my-4" />
        <div className="row g-3 justify-content-center">
          <div className="col-md-4">
            <div className="p-3 border rounded bg-light">
              <h5>Active Projects</h5>
              <p className="h2 text-primary">03</p>
            </div>
          </div>
          <div className="col-md-4">
            <div className="p-3 border rounded bg-light">
              <h5>Pending Payments</h5>
              <p className="h2 text-danger">$150</p>
            </div>
          </div>
        </div>
        <button onClick={handleLogout} className="btn btn-outline-danger mt-5 px-4 fw-bold">
          Logout Session
        </button>
      </div>
    </div>
  );
}

export default ClientDashboard;
